1	type Item = { type: string; enchantment?: number; cursed?: boolean };
2	type Scenario = {
3	  customer?: { yearsWithMHPCO?: number };
4	  steps: Array<{ op: string; items?: Item[] }>;
5	};
6	
7	const PROCESSING_FEE = 5;
8	const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	  staff: 80,
12	  potion: 40,
13	  rune: 25,
14	  moonstone: 25,
15	};
16	const BLOCK_OF_3_PRICE = 60;
17	const BLOCK_ELIGIBLE_TYPES = new Set(["rune", "moonstone"]);
18	const HIGH_ENCHANTMENT_THRESHOLD = 5;
19	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
20	const CURSE_SURCHARGE_RATE = 0.5;
21	const LOYALTY_THRESHOLD_YEARS = 2;
22	const LOYALTY_DISCOUNT_RATE = 0.2;
23	const FIRST_INSURANCE_RATE = 0.1;
24	
25	function quotePremium(items: Item[], yearsWithMHPCO: number): number {
26	  const countsByType: Record<string, number> = {};
27	  for (const item of items) {
28	    countsByType[item.type] = (countsByType[item.type] ?? 0) + 1;
29	  }
30	  let policyBase = 0;
31	  for (const [type, count] of Object.entries(countsByType)) {
32	    if (BLOCK_ELIGIBLE_TYPES.has(type) && count === 3) {
33	      policyBase += BLOCK_OF_3_PRICE;
34	    } else {
35	      policyBase += count * BASE_PREMIUM_BY_ITEM_TYPE[type];
36	    }
37	  }
38	  let itemSurcharges = 0;
39	  for (const item of items) {
40	    let rate = 0;
41	    if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
42	      rate += HIGH_ENCHANTMENT_SURCHARGE_RATE;
43	    }
44	    if (item.cursed) {
45	      rate += CURSE_SURCHARGE_RATE;
46	    }
47	    itemSurcharges += rate * BASE_PREMIUM_BY_ITEM_TYPE[item.type];
48	  }
49	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
50	  const loyaltyDiscount =
51	    yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? policyBase * LOYALTY_DISCOUNT_RATE : 0;
52	  return (
53	    Math.ceil(policyBase + itemSurcharges + firstInsurance - loyaltyDiscount) +
54	    PROCESSING_FEE
55	  );
56	}
57	
58	export function processScenario(scenario: unknown): unknown {
59	  const { customer, steps } = scenario as Scenario;
60	  const yearsWithMHPCO = customer?.yearsWithMHPCO ?? 0;
61	  const results = steps.map((step) => ({
62	    premium: quotePremium(step.items ?? [], yearsWithMHPCO),
63	  }));
64	  return { results };
65	}
